def retrieve_data_from_accounting_system(start_date, end_date):
    # Assume this function retrieves data from QuickBooks or Sage
    data = []
    with open('accounting_data.csv', 'r') as csvfile:
        reader = csv.DictReader(csvfile)
        for row in reader:
            transaction_date = datetime.datetime.strptime(row['Date'], '%Y-%m-%d')
            if start_date <= transaction_date <= end_date:
                data.append(row)
    return data

def generate_monthly_report(data, start_date, end_date):
    # Generate monthly report
    report = {}
    current_month = start_date.month
    while start_date.month <= end_date.month:
        report[start_date.strftime('%B')] = {
            'revenue': sum([float(row['Amount']) for row in data if row['Date'].startswith(start_date.strftime('%Y-%m'))]),
            'expenses': sum([float(row['Amount']) for row in data if row['Date'].startswith(start_date.strftime('%Y-%m')) and float(row['Amount']) < 0])
        }
        start_date = start_date.replace(day=1) + datetime.timedelta(days=32).replace(day=1)
    save_report(report, 'monthly_report.csv')

def generate_quarterly_report(data, start_date, end_date):
    # Generate quarterly report
    report = {}
    quarters = [
        ('Q1', (1, 2, 3)), ('Q2', (4, 5, 6)),
        ('Q3', (7, 8, 9)), ('Q4', (10, 11, 12))
    ]
    for quarter, months in quarters:
        if start_date.month in months or end_date.month in months:
            report[quarter] = {
                'revenue': sum([float(row['Amount']) for row in data if row['Date'].split('-')[1] in [str(m) for m in months]]),
                'expenses': sum([float(row['Amount']) for row in data if row['Date'].split('-')[1] in [str(m) for m in months] and float(row['Amount']) < 0])
            }
    save_report(report, 'quarterly_report.csv')

def generate_annual_report(data, start_date, end_date):
    # Generate annual report
    report = {
        'revenue': sum([float(row['Amount']) for row in data if row['Date'].startswith(str(start_date.year))]),
        'expenses': sum([float(row['Amount']) for row in data if row['Date'].startswith(str(start_date.year)) and float(row['Amount']) < 0])
    }
    save_report(report, 'annual_report.csv')

def save_report(report, filename):
    with open(filename, 'w', newline='') as csvfile:
        fieldnames = ['Period', 'Revenue', 'Expenses']
        writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
        writer.writeheader()
        for period, data in report.items():
            writer.writerow({'Period': period, 'Revenue': data['revenue'], 'Expenses': data['expenses']})

