class FinancialStatements:
    def __init__(self, data_source, time_period='monthly'):
        self.data_source = data_source
        self.time_period = time_period
        self.data = self.load_data()

    def load_data(self):
        if self.data_source == 'quickbooks':
            return self.load_quickbooks_data()
        elif self.data_source == 'sage':
            return self.load_sage_data()
        else:
            raise ValueError('Invalid data source. Please use "quickbooks" or "sage".')

    def load_quickbooks_data(self):
        # Code to fetch data from QuickBooks
        with open('quickbooks_data.json', 'r') as f:
            return json.load(f)

    def load_sage_data(self):
        # Code to fetch data from Sage
        with open('sage_data.csv', 'r') as f:
            reader = csv.DictReader(f)
            return [row for row in reader]

    def generate_income_statement(self):
        income_statement = {
            'revenue': 0,
            'cost_of_goods_sold': 0,
            'gross_profit': 0,
            'operating_expenses': 0,
            'net_income': 0
        }

        for transaction in self.data:
            if transaction['type'] == 'revenue':
                income_statement['revenue'] += transaction['amount']
            elif transaction['type'] == 'cost_of_goods_sold':
                income_statement['cost_of_goods_sold'] += transaction['amount']
            elif transaction['type'] == 'operating_expense':
                income_statement['operating_expenses'] += transaction['amount']

        income_statement['gross_profit'] = income_statement['revenue'] - income_statement['cost_of_goods_sold']
        income_statement['net_income'] = income_statement['gross_profit'] - income_statement['operating_expenses']

        return income_statement

    def generate_balance_sheet(self):
        balance_sheet = {
            'assets': {
                'current_assets': 0,
                'non_current_assets': 0,
                'total_assets': 0
            },
            'liabilities': {
                'current_liabilities': 0,
                'non_current_liabilities': 0,
                'total_liabilities': 0
            },
            'equity': 0
        }

        for transaction in self.data:
            if transaction['type'] == 'asset':
                if transaction['asset_type'] == 'current':
                    balance_sheet['assets']['current_assets'] += transaction['amount']
                else:
                    balance_sheet['assets']['non_current_assets'] += transaction['amount']
            elif transaction['type'] == 'liability':
                if transaction['liability_type'] == 'current':
                    balance_sheet['liabilities']['current_liabilities'] += transaction['amount']
                else:
                    balance_sheet['liabilities']['non_current_liabilities'] += transaction['amount']
            elif transaction['type'] == 'equity':
                balance_sheet['equity'] += transaction['amount']

        balance_sheet['assets']['total_assets'] = balance_sheet['assets']['current_assets'] + balance_sheet['assets']['non_current_assets']
        balance_sheet['liabilities']['total_liabilities'] = balance_sheet['liabilities']['current_liabilities'] + balance_sheet['liabilities']['non_current_liabilities']

        return balance_sheet

    def generate_cash_flow_statement(self):
        cash_flow_statement = {
            'operating_activities': 0,
            'investing_activities': 0,
            'financing_activities': 0,
            'net_cash_flow': 0
        }

        for transaction in self.data:
            if transaction['type'] == 'operating':
                cash_flow_statement['operating_activities'] += transaction['amount']
            elif transaction['type'] == 'investing':
                cash_flow_statement['investing_activities'] += transaction['amount']
            elif transaction['type'] == 'financing':
                cash_flow_statement['financing_activities'] += transaction['amount']

        cash_flow_statement['net_cash_flow'] = cash_flow_statement['operating_activities'] + cash_flow_statement['investing_activities'] + cash_flow_statement['financing_activities']

